/**
 * RTK Query API slice — central hub for all server communication.
 * Each endpoint automatically generates hooks like:
 *   useGetFoodLogsQuery, useAddFoodLogMutation, etc.
 */
import { createApi, fetchBaseQuery } from "@reduxjs/toolkit/query/react";

// ─── Shared Types ─────────────────────────────────────────────────────────────

export type FoodLog = {
  id: string;
  fdc_id: number;
  food_name: string;
  calories: number | null;
  protein: number | null;
  carbs: number | null;
  fat: number | null;
  fiber: number | null;
  sodium: number | null;
  saturated_fat: number | null;
  trans_fat: number | null;
  polyunsaturated_fat: number | null;
  monounsaturated_fat: number | null;
  cholesterol: number | null;
  sugars: number | null;
  added_sugars: number | null;
  vitamin_a: number | null;
  vitamin_c: number | null;
  vitamin_d: number | null;
  vitamin_e: number | null;
  vitamin_k: number | null;
  thiamin: number | null;
  riboflavin: number | null;
  niacin: number | null;
  vitamin_b6: number | null;
  folate: number | null;
  vitamin_b12: number | null;
  calcium: number | null;
  iron: number | null;
  magnesium: number | null;
  phosphorus: number | null;
  potassium: number | null;
  zinc: number | null;
  selenium: number | null;
  quantity: number;
  time: string;
  date?: string;
  meal_type?: string;
};

export type UserGoal = {
  calories_goal: number | null;
  protein_goal: number | null;
  carbs_goal: number | null;
  fat_goal: number | null;
};

export type UsdaFood = {
  fdcId: number;
  description: string;
  dataType?: string;
  brandOwner?: string;
  /** "usda" | "off" | "custom" — set by clients, not the API */
  source?: string;
  /** id of CustomFood row when source === "custom" */
  customFoodId?: string;
  foodNutrients?: Array<{
    nutrientName: string;
    value: number;
    unitName: string;
  }>;
};

export type GroceryItem = {
  id: string;
  food_name: string;
  quantity: number;
  unit: string | null;
  purchased: boolean;
  category: string | null;
};

export type Favorite = {
  id: string;
  fdc_id: number;
  food_name: string;
  calories: number | null;
  protein: number | null;
  carbs: number | null;
  fat: number | null;
  serving_size: number | null;
};

export type CustomFood = {
  id: string;
  name: string;
  serving_size: number | null;
  serving_unit: string;
  category: string | null;
  barcode: string | null;
  calories: number | null;
  protein: number | null;
  carbs: number | null;
  fat: number | null;
  fiber: number | null;
  sodium: number | null;
  created_at: string;
  updated_at: string;
};

export type UserRecipe = {
  id: string;
  title: string;
  description: string | null;
  ingredients: string[];
  instructions: string | null;
  servings: number;
  prep_time: number | null;
  cook_time: number | null;
  image_url: string | null;
  calories: number | null;
  protein: number | null;
  carbs: number | null;
  fat: number | null;
  fiber: number | null;
  sodium: number | null;
  created_at: string;
  updated_at: string;
};

export type SavedRecipe = {
  id: string;
  spoonacular_id: number;
  title: string;
  image: string | null;
  servings: number | null;
  ready_in_minutes: number | null;
  calories: number | null;
  protein: number | null;
  carbs: number | null;
  fat: number | null;
  created_at: string;
};

export type WeightLog = {
  id: string;
  weight_lbs: number;
  note: string | null;
  logged_at: string;  // YYYY-MM-DD
  created_at: string;
};

// ─── RTK Query API ────────────────────────────────────────────────────────────

export const api = createApi({
  reducerPath: "api",
  baseQuery: fetchBaseQuery({ baseUrl: "/" }),
  tagTypes: ["FoodLog", "Goals", "Grocery", "Favorites", "CustomFoods", "UserRecipes", "SavedRecipes", "WeightLogs"],

  endpoints: (builder) => ({
    // ── Food Logs ──────────────────────────────────────────────────────────
    getFoodLogs: builder.query<FoodLog[], { date?: string; start?: string; end?: string }>({
      query: ({ date, start, end }) => {
        const params = new URLSearchParams();
        if (date) params.set("date", date);
        if (start) params.set("start", start);
        if (end) params.set("end", end);
        return `api/food-logs?${params}`;
      },
      transformResponse: (res: { logs: FoodLog[] }) => res.logs ?? [],
      providesTags: (result) =>
        result
          ? [...result.map(({ id }) => ({ type: "FoodLog" as const, id })), { type: "FoodLog", id: "LIST" }]
          : [{ type: "FoodLog", id: "LIST" }],
    }),

    addFoodLog: builder.mutation<FoodLog, Partial<FoodLog>>({
      query: (body) => ({ url: "api/food-logs", method: "POST", body }),
      invalidatesTags: [{ type: "FoodLog", id: "LIST" }],
    }),

    updateFoodLog: builder.mutation<FoodLog, Partial<FoodLog> & { id: string }>({
      query: (body) => ({ url: "api/food-logs", method: "PATCH", body }),
      invalidatesTags: (_result, _err, { id }) => [{ type: "FoodLog", id }],
    }),

    deleteFoodLog: builder.mutation<void, string>({
      query: (id) => ({ url: `api/food-logs?id=${id}`, method: "DELETE" }),
      invalidatesTags: (_result, _err, id) => [{ type: "FoodLog", id }, { type: "FoodLog", id: "LIST" }],
    }),

    // ── User Goals ────────────────────────────────────────────────────────
    getUserGoals: builder.query<UserGoal | null, void>({
      query: () => "api/user-goals",
      transformResponse: (res: { goals: UserGoal | null }) => res.goals,
      providesTags: ["Goals"],
    }),

    updateUserGoals: builder.mutation<UserGoal, Partial<UserGoal>>({
      query: (body) => ({ url: "api/user-goals", method: "POST", body }),
      invalidatesTags: ["Goals"],
    }),

    // ── Food Search ───────────────────────────────────────────────────────
    searchFoods: builder.query<UsdaFood[], string>({
      query: (q) => `api/foods/search?query=${encodeURIComponent(q)}&pageSize=5`,
      transformResponse: (res: { foods: UsdaFood[] }) => {
        const seen = new Set<string>();
        return (res.foods ?? [])
          .filter((f) => {
            const key = f.description.toLowerCase().trim();
            if (seen.has(key)) return false;
            seen.add(key);
            return true;
          })
          .slice(0, 5);
      },
    }),

    getFoodDetail: builder.query<{
      description: string;
      foodNutrients: Array<{ nutrient?: { name: string }; nutrientName?: string; amount?: number; value?: number }>;
    }, number>({
      query: (fdcId) => `api/foods/${fdcId}`,
    }),

    // ── Grocery ───────────────────────────────────────────────────────────
    getGroceryItems: builder.query<GroceryItem[], void>({
      query: () => "api/grocery",
      transformResponse: (res: { items: GroceryItem[] }) => res.items ?? [],
      providesTags: (result) =>
        result
          ? [...result.map(({ id }) => ({ type: "Grocery" as const, id })), { type: "Grocery", id: "LIST" }]
          : [{ type: "Grocery", id: "LIST" }],
    }),

    addGroceryItem: builder.mutation<GroceryItem, { food_name: string; quantity?: number; unit?: string }>({
      query: (body) => ({ url: "api/grocery", method: "POST", body }),
      invalidatesTags: [{ type: "Grocery", id: "LIST" }],
    }),

    updateGroceryItem: builder.mutation<GroceryItem, Partial<GroceryItem> & { id: string }>({
      query: (body) => ({ url: "api/grocery", method: "PATCH", body }),
      invalidatesTags: (_result, _err, { id }) => [{ type: "Grocery", id }],
    }),

    deleteGroceryItem: builder.mutation<void, string>({
      query: (id) => ({ url: `api/grocery?id=${id}`, method: "DELETE" }),
      invalidatesTags: [{ type: "Grocery", id: "LIST" }],
    }),

    // ── Favorites ─────────────────────────────────────────────────────────
    getFavorites: builder.query<Favorite[], void>({
      query: () => "api/favorites",
      transformResponse: (res: { favorites: Favorite[] }) => res.favorites ?? [],
      providesTags: (result) =>
        result
          ? [...result.map(({ id }) => ({ type: "Favorites" as const, id })), { type: "Favorites", id: "LIST" }]
          : [{ type: "Favorites", id: "LIST" }],
    }),

    addFavorite: builder.mutation<Favorite, Partial<Favorite>>({
      query: (body) => ({ url: "api/favorites", method: "POST", body }),
      invalidatesTags: [{ type: "Favorites", id: "LIST" }],
    }),

    deleteFavorite: builder.mutation<void, string>({
      query: (id) => ({ url: `api/favorites?id=${id}`, method: "DELETE" }),
      invalidatesTags: [{ type: "Favorites", id: "LIST" }],
    }),

    // ── Custom Foods ──────────────────────────────────────────────────────
    getCustomFoods: builder.query<CustomFood[], string>({
      query: (q) => `api/foods/custom${q ? `?q=${encodeURIComponent(q)}` : ""}`,
      transformResponse: (res: { foods: CustomFood[] }) => res.foods ?? [],
      providesTags: (result) =>
        result
          ? [...result.map(({ id }) => ({ type: "CustomFoods" as const, id })), { type: "CustomFoods", id: "LIST" }]
          : [{ type: "CustomFoods", id: "LIST" }],
    }),

    createCustomFood: builder.mutation<CustomFood, Omit<CustomFood, "id" | "created_at" | "updated_at">>({
      query: (body) => ({ url: "api/foods/custom", method: "POST", body }),
      transformResponse: (res: { food: CustomFood }) => res.food,
      invalidatesTags: [{ type: "CustomFoods", id: "LIST" }],
    }),

    updateCustomFood: builder.mutation<CustomFood, Partial<CustomFood> & { id: string }>({
      query: (body) => ({ url: "api/foods/custom", method: "PATCH", body }),
      transformResponse: (res: { food: CustomFood }) => res.food,
      invalidatesTags: (_res, _err, { id }) => [{ type: "CustomFoods", id }, { type: "CustomFoods", id: "LIST" }],
    }),

    deleteCustomFood: builder.mutation<void, string>({
      query: (id) => ({ url: `api/foods/custom?id=${id}`, method: "DELETE" }),
      invalidatesTags: (_res, _err, id) => [{ type: "CustomFoods", id }, { type: "CustomFoods", id: "LIST" }],
    }),

    // ── Streak ──────────────────────────────────────────────────────
    getStreak: builder.query<{ streak: number; longestStreak: number }, void>({
      query: () => "api/streak",
      transformResponse: (res: { streak: number; longestStreak: number }) => res,
    }),

    // ── User Recipes (CRUD) ───────────────────────────────────────────────
    getUserRecipes: builder.query<UserRecipe[], void>({
      query: () => "api/recipes/user-recipes",
      transformResponse: (res: { recipes: UserRecipe[] }) => res.recipes ?? [],
      providesTags: (result) =>
        result
          ? [...result.map(({ id }) => ({ type: "UserRecipes" as const, id })), { type: "UserRecipes", id: "LIST" }]
          : [{ type: "UserRecipes", id: "LIST" }],
    }),

    createUserRecipe: builder.mutation<UserRecipe, Omit<UserRecipe, "id" | "created_at" | "updated_at">>({
      query: (body) => ({ url: "api/recipes/user-recipes", method: "POST", body }),
      transformResponse: (res: { recipe: UserRecipe }) => res.recipe,
      invalidatesTags: [{ type: "UserRecipes", id: "LIST" }],
    }),

    updateUserRecipe: builder.mutation<UserRecipe, Partial<UserRecipe> & { id: string }>({
      query: ({ id, ...body }) => ({ url: `api/recipes/user-recipes/${id}`, method: "PUT", body }),
      transformResponse: (res: { recipe: UserRecipe }) => res.recipe,
      invalidatesTags: (_res, _err, { id }) => [{ type: "UserRecipes", id }, { type: "UserRecipes", id: "LIST" }],
    }),

    deleteUserRecipe: builder.mutation<void, string>({
      query: (id) => ({ url: `api/recipes/user-recipes/${id}`, method: "DELETE" }),
      invalidatesTags: (_res, _err, id) => [{ type: "UserRecipes", id }, { type: "UserRecipes", id: "LIST" }],
    }),

    // ── Saved (Bookmarked) Spoonacular Recipes ────────────────────────────
    getSavedRecipes: builder.query<SavedRecipe[], void>({
      query: () => "api/recipes/saved",
      transformResponse: (res: { saved: SavedRecipe[] }) => res.saved ?? [],
      providesTags: [{ type: "SavedRecipes", id: "LIST" }],
    }),

    saveRecipe: builder.mutation<SavedRecipe, Omit<SavedRecipe, "id" | "created_at">>({
      query: (body) => ({ url: "api/recipes/saved", method: "POST", body }),
      transformResponse: (res: { saved: SavedRecipe }) => res.saved,
      invalidatesTags: [{ type: "SavedRecipes", id: "LIST" }],
    }),

    unsaveRecipe: builder.mutation<void, number>({
      query: (id) => ({ url: `api/recipes/saved?id=${id}`, method: "DELETE" }),
      invalidatesTags: [{ type: "SavedRecipes", id: "LIST" }],
    }),

    // ── Weight Logs ───────────────────────────────────────────────────
    getWeightLogs: builder.query<WeightLog[], { days?: number } | void>({
      query: (arg) => `api/weight${arg?.days ? `?days=${arg.days}` : ""}`,
      transformResponse: (res: { logs: WeightLog[] }) => res.logs ?? [],
      providesTags: [{ type: "WeightLogs", id: "LIST" }],
    }),

    addWeightLog: builder.mutation<WeightLog, { weight_lbs: number; note?: string; logged_at?: string }>({
      query: (body) => ({ url: "api/weight", method: "POST", body }),
      transformResponse: (res: { log: WeightLog }) => res.log,
      invalidatesTags: [{ type: "WeightLogs", id: "LIST" }],
    }),

    deleteWeightLog: builder.mutation<void, string>({
      query: (id) => ({ url: `api/weight?id=${id}`, method: "DELETE" }),
      invalidatesTags: [{ type: "WeightLogs", id: "LIST" }],
    }),
  }),
});

// Auto-generated hooks
export const {
  useGetFoodLogsQuery,
  useAddFoodLogMutation,
  useUpdateFoodLogMutation,
  useDeleteFoodLogMutation,
  useGetUserGoalsQuery,
  useUpdateUserGoalsMutation,
  useSearchFoodsQuery,
  useLazySearchFoodsQuery,
  useGetFoodDetailQuery,
  useLazyGetFoodDetailQuery,
  useGetGroceryItemsQuery,
  useAddGroceryItemMutation,
  useUpdateGroceryItemMutation,
  useDeleteGroceryItemMutation,
  useGetFavoritesQuery,
  useAddFavoriteMutation,
  useDeleteFavoriteMutation,
  useGetCustomFoodsQuery,
  useCreateCustomFoodMutation,
  useUpdateCustomFoodMutation,
  useDeleteCustomFoodMutation,
  useGetStreakQuery,
  useGetUserRecipesQuery,
  useCreateUserRecipeMutation,
  useUpdateUserRecipeMutation,
  useDeleteUserRecipeMutation,
  useGetSavedRecipesQuery,
  useSaveRecipeMutation,
  useUnsaveRecipeMutation,
  useGetWeightLogsQuery,
  useAddWeightLogMutation,
  useDeleteWeightLogMutation,
} = api;
